-- ============================================\n-- ASSIGNMENT 2: BASIC SELECT QUERIES\n-- Filtering, Sorting, and Projections\n-- ============================================\n-- This assignment tests your ability to:\n-- 1. Write SELECT queries with WHERE clauses\n-- 2. Use logical operators (AND, OR, NOT)\n-- 3. Sort results with ORDER BY\n-- 4. Use pattern matching with LIKE\n-- 5. Handle NULL values properly\n\nUSE practice_db;\n\n-- Setup: Create and populate test tables\nCREATE TABLE IF NOT EXISTS employees (\n    emp_id INT PRIMARY KEY,\n    first_name VARCHAR(50),\n    last_name VARCHAR(50),\n    email VARCHAR(100),\n    salary DECIMAL(10,2),\n    department VARCHAR(50),\n    hire_date DATE\n);\n\nINSERT IGNORE INTO employees VALUES\n(1, 'Alice', 'Smith', 'alice@company.com', 90000, 'Sales', '2020-01-15'),\n(2, 'Bob', 'Johnson', 'bob@company.com', 75000, 'IT', '2021-03-20'),\n(3, 'Charlie', 'Brown', 'charlie@company.com', 70000, 'Sales', '2022-06-10'),\n(4, 'Diana', 'Davis', 'diana@company.com', 65000, 'HR', '2023-02-01'),\n(5, 'Eve', 'Wilson', NULL, 62000, 'IT', '2023-05-12'),\n(6, 'Frank', 'Miller', 'frank@company.com', 72000, 'Finance', '2023-07-01'),\n(7, 'Grace', 'Taylor', NULL, 68000, 'Sales', '2023-08-15');\n\n-- ============================================\n-- PROBLEM 1: Select Specific Columns\n-- ============================================\n-- Write a query to display first_name, last_name, and salary\n-- for all employees\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 7 rows with 3 columns\n\n\n-- ============================================\n-- PROBLEM 2: Filter with WHERE\n-- ============================================\n-- Find all employees in the 'Sales' department\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 3 rows (Alice, Charlie, Grace)\n\n\n-- ============================================\n-- PROBLEM 3: WHERE with Comparison\n-- ============================================\n-- Find all employees earning more than $70,000\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 4 rows (Alice, Bob, Charlie, Frank)\n\n\n-- ============================================\n-- PROBLEM 4: AND Operator\n-- ============================================\n-- Find employees in Sales department earning more than $70,000\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 2 rows (Alice, Charlie)\n\n\n-- ============================================\n-- PROBLEM 5: OR Operator\n-- ============================================\n-- Find employees earning more than $80,000 OR in IT department\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 3 rows (Alice, Bob, Eve)\n\n\n-- ============================================\n-- PROBLEM 6: NOT Operator\n-- ============================================\n-- Find employees NOT in the Sales department\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 4 rows (Bob, Diana, Eve, Frank)\n\n\n-- ============================================\n-- PROBLEM 7: LIKE Pattern Matching\n-- ============================================\n-- Find all employees whose first name starts with 'A' or 'E'\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 2 rows (Alice, Eve)\n\n\n-- ============================================\n-- PROBLEM 8: BETWEEN Operator\n-- ============================================\n-- Find employees earning between $65,000 and $75,000 (inclusive)\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 4 rows (Bob, Charlie, Diana, Frank)\n\n\n-- ============================================\n-- PROBLEM 9: ORDER BY\n-- ============================================\n-- List all employees sorted by salary in descending order\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: Highest salary first (Alice 90000) to lowest (Eve 62000)\n\n\n-- ============================================\n-- PROBLEM 10: Multiple Sorting\n-- ============================================\n-- Sort employees by department (alphabetically), then by salary (high to low)\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: Finance first, then HR, IT, Sales - within each, highest salary first\n\n\n-- ============================================\n-- PROBLEM 11: NULL Handling\n-- ============================================\n-- Find all employees with NULL email addresses\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 2 rows (Eve, Grace)\n\n\n-- ============================================\n-- PROBLEM 12: Complex WHERE Clause\n-- ============================================\n-- Find employees who:\n-- - Are in Sales department\n-- - AND earn more than $65,000\n-- - AND have a valid email\n-- Order by salary descending\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 2 rows (Alice, Charlie)\n\n\n-- ============================================\n-- PROBLEM 13: IN Operator\n-- ============================================\n-- Find employees in IT, HR, or Finance departments\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 4 rows\n\n\n-- ============================================\n-- PROBLEM 14: Combination of Operators\n-- ============================================\n-- Find employees who:\n-- - Have email (NOT NULL)\n-- - Work in Sales or IT\n-- - Earn more than $68,000\n-- Order by first name\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 3 rows (Alice, Bob, Charlie)\n\n\n-- ============================================\n-- PROBLEM 15: LIMIT and ORDER BY\n-- ============================================\n-- Find the top 3 highest-paid employees\n\n-- YOUR SOLUTION HERE:\n-- SELECT ...\n\n-- Expected: 3 rows (Alice 90000, Bob 75000, Frank 72000)\n\n\n-- ============================================\n-- EXPECTED OUTPUTS SUMMARY\n-- ============================================\n-- Problem 1: 7 rows, 3 columns\n-- Problem 2: Alice, Charlie, Grace\n-- Problem 3: Alice, Bob, Charlie, Frank (4 rows)\n-- Problem 4: Alice, Charlie (2 rows)\n-- Problem 5: Alice, Bob, Eve (3 rows)\n-- Problem 6: 4 rows (Bob, Diana, Eve, Frank)\n-- Problem 7: Alice, Eve (2 rows)\n-- Problem 8: 4 rows (salary between 65k-75k)\n-- Problem 9: Sorted high to low\n-- Problem 10: Grouped by dept, then sorted by salary\n-- Problem 11: Eve, Grace (NULL emails)\n-- Problem 12: Alice, Charlie (2 rows)\n-- Problem 13: Bob, Diana, Eve, Frank (4 rows)\n-- Problem 14: Alice, Bob, Charlie (3 rows)\n-- Problem 15: Top 3 by salary\n\n\n-- ============================================\n-- BONUS CHALLENGES\n-- ============================================\n\n-- BONUS 1: Case Sensitivity\n-- Find all employees matching 'alice' (test case sensitivity)\n\n-- BONUS 2: Date Range\n-- Find employees hired after January 1, 2023\n\n-- BONUS 3: Email Pattern\n-- Find employees whose email contains 'company.com'\n\n-- BONUS 4: Salary Statistics\n-- Display employees with salary formatted to show annual amount\n-- (Show monthly_salary and annual_salary)\n\n-- BONUS 5: Combine Multiple Conditions\n-- Complex query combining multiple filters, sorting, and limiting\n\n\n-- ============================================\n-- LEARNING OUTCOMES\n-- ============================================\n-- After completing this assignment, you should be able to:\n-- ✅ Write SELECT queries with multiple conditions\n-- ✅ Use WHERE clauses effectively\n-- ✅ Apply AND, OR, NOT operators correctly\n-- ✅ Use LIKE for pattern matching\n-- ✅ Handle NULL values in queries\n-- ✅ Sort results with ORDER BY\n-- ✅ Limit results with LIMIT\n-- ✅ Combine multiple conditions logically\n-- ✅ Read and understand complex WHERE clauses\n"